  ('elementary-f29af906-moex-00488', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，湖澤及可通運之水道及岸地，如因水流變遷而自然增加時，何人有優先依法取得 其所有權或使用受益之權？', '["其毗鄰地之使用人", "原水道及岸地之所有權人", "土地之管理機關", "其接連地之所有權人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00489', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，直轄市或縣（市）政府對於其所管公有土地，非經甲同意，並經乙核准，不得處 分或設定負擔或為超過10年期間之租賃。前述之甲、乙指那些機關？', '["甲：該管區內民意機關；乙：行政院", "甲：直轄市或縣（市）財政局；乙：財政部", "甲：內政部；乙：行政院", "甲：地政司；乙：內政部"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00490', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，外國人為供自用、投資或公益之目的使用，得取得一定用途之土地，該管直轄市 或縣（市）政府依法得為一定之限制。請問該限制所指為何？', '["面積及所在地點", "區位及交易範圍", "交易價格與面積", "公益與否與市場"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00491', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '甲、乙、丙、丁、戊共有一土地，甲、乙持分各1/3，丙、丁、戊持分各1/9。依土地法與相關規定， 下列選項何者正確？', '["甲、乙二人同意，得處分該共有土地", "丙、丁、戊三人同意，得處分該共有土地", "甲、乙、丙、丁同意，欲處分該共有土地，戊得主張該共有土地的優先購買權", "甲欲出賣其應有部分，丙和丁無法以同一價格共同優先承購"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00492', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於建物全部滅失時，依土地登記規則之規定，下列敘述何者錯誤？', '["該建物所有權人未於規定期限內申請消滅登記者，得由土地所有權人或其他權利人代位申請", "建物基地有法定地上權登記者，應同時辦理該地上權塗銷登記", "登記機關於登記完畢後，應將登記結果通知承租人", "建物全部滅失時，得由登記機關查明後逕為辦理消滅登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00493', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，申請建物所有權第一次登記，於計收登記規費時，關於其權利價值之認定， 下列敘述何者正確？', '["建物在依法實施建築管理地區者，應以使用執照所列工程造價為準", "建物在依法實施建築管理地區者，應以實價登錄之價格為準", "建物在依法實施建築管理地區者，應以當地稅捐稽徵機關所核定之房屋現值為準", "建物在依法實施建築管理地區者，應以當地地價評議委員會所核定之房屋現值為準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00494', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於土地法地籍編通則章之規定，下列選項何者錯誤？', '["地籍整理之程序，為地籍測量及土地登記", "土地登記，謂土地及建築改良物之所有權與他項權利之登記", "地籍整理以直轄市或縣（市）為單位，直轄市或縣（市）分區，區內分段，段內分宗，按宗編號", "土地總登記，謂於一定期間內就直轄市或縣（市）之私有土地全部為土地登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
