  ('elementary-f29af906-moex-00496', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，建物標示圖申請建物所有權第一次登記，申請人與委託繪製人不同時，應 如何處理？', '["應不得辦理", "應於登記申請書適當欄記明同意依該圖繪製成果辦理登記，並簽名或蓋章", "應於登記申請書記明建物起造人及繪製人願負法律責任等字樣及開業證照字號，並簽名或蓋章", "應由開業之建築師、測量技師或其他依法規得為測量相關簽證之專門職業及技術人員於登記申請 書簽證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00497', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，實施建築管理前建造之建物，無使用執照者，應提出主管建築機關或鄉（鎮、 市、區）公所之證明文件或實施建築管理前有關該建物之文件。下列選項何者並非前述之文件？', '["繳納水費憑證、電費憑證", "曾於該建物設籍之戶籍證明文件", "繳納房屋稅憑證或稅籍證明", "原屋主之切結書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
